#include <bits/stdc++.h>
using namespace std;
#define int long long
int l,r,ans;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>l>>r;
	for(int i1=0; i1<=3; i1++) {
		for(int i2=0; i2<=3; i2++) {
			for(int i3=0; i3<=3; i3++) {
				for(int i4=0; i4<=3; i4++) {
					for(int i5=0; i5<=3; i5++) {
						for(int i6=0; i6<=3; i6++) {
							for(int i7=0; i7<=3; i7++) {
								for(int i8=0; i8<=3; i8++) {
									for(int i9=0; i9<=3; i9++) {
										for(int i=0; i<=3; i++) {
											int a=i1+i2*1e1+i3*1e2+i4*1e3+i5*1e4+i6*1e5+i7*1e6+i8*1e7+i9*1e8+i*1e9;
											if(a<l||a>r){
												continue;
											}
											int b=a*a;
											int x=0,xx=0;
											while(a){
												x+=a%10;
												a/=10;
											}
											while(b){
												xx+=b%10;
												b/=10;
											}
											if(x*x==xx){
												ans++;
											}
										}
									}
								}
							}
						}
					}
				}
			}
		}
	}
	cout<<ans;
	return 0;
}
